CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

CREATE TABLE IF NOT EXISTS upload_jobs (
    id            VARCHAR(36) PRIMARY KEY,
    filename      VARCHAR(255) NOT NULL,
    status        VARCHAR(20)  NOT NULL DEFAULT 'uploading',
    total_rows    BIGINT       NOT NULL DEFAULT 0,
    processed_rows BIGINT      NOT NULL DEFAULT 0,
    error_message TEXT,
    upload_started_at    TIMESTAMPTZ,
    upload_finished_at   TIMESTAMPTZ,
    processing_started_at  TIMESTAMPTZ,
    processing_finished_at TIMESTAMPTZ,
    created_at    TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS students (
    id          BIGSERIAL PRIMARY KEY,
    student_id  VARCHAR(36)  NOT NULL,
    student_name VARCHAR(255) NOT NULL,
    subject     VARCHAR(100) NOT NULL,
    grade       INTEGER      NOT NULL,
    job_id      VARCHAR(36)  REFERENCES upload_jobs(id) ON DELETE SET NULL,
    created_at  TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_students_student_name ON students (student_name);
CREATE INDEX IF NOT EXISTS idx_students_subject      ON students (subject);
CREATE INDEX IF NOT EXISTS idx_students_grade        ON students (grade);
CREATE INDEX IF NOT EXISTS idx_students_job_id       ON students (job_id);

