package progress

import (
	"sync"
	"time"

	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/models"
)

// Event is the payload broadcast to SSE subscribers.
type Event struct {
	JobID         string            `json:"job_id"`
	Status        models.JobStatus  `json:"status"`
	TotalRows     int64             `json:"total_rows"`
	ProcessedRows int64             `json:"processed_rows"`
	Percentage    float64           `json:"percentage"`
	ErrorMessage  string            `json:"error_message,omitempty"`

	UploadStartedAt      *time.Time `json:"upload_started_at,omitempty"`
	UploadFinishedAt     *time.Time `json:"upload_finished_at,omitempty"`
	ProcessingStartedAt  *time.Time `json:"processing_started_at,omitempty"`
	ProcessingFinishedAt *time.Time `json:"processing_finished_at,omitempty"`
}

type job struct {
	mu          sync.RWMutex
	event       Event
	subscribers map[string]chan Event // connID -> channel
}

// Tracker is a thread-safe, in-memory store for job progress.
// It broadcasts updates to all SSE subscribers of a job.
type Tracker struct {
	mu   sync.RWMutex
	jobs map[string]*job
}

func NewTracker() *Tracker {
	return &Tracker{jobs: make(map[string]*job)}
}

// Create registers a new job.
func (t *Tracker) Create(jobID, filename string) {
	now := time.Now()
	t.mu.Lock()
	defer t.mu.Unlock()
	t.jobs[jobID] = &job{
		event: Event{
			JobID:           jobID,
			Status:          models.StatusUploading,
			UploadStartedAt: &now,
		},
		subscribers: make(map[string]chan Event),
	}
}

// MarkUploadDone transitions the job to processing state.
func (t *Tracker) MarkUploadDone(jobID string, totalRows int64) {
	now := time.Now()
	t.withJob(jobID, func(j *job) {
		j.event.Status = models.StatusProcessing
		j.event.TotalRows = totalRows
		j.event.UploadFinishedAt = &now
		j.event.ProcessingStartedAt = &now
		t.broadcast(j)
	})
}

// UpdateProgress increments processed rows and broadcasts to subscribers.
func (t *Tracker) UpdateProgress(jobID string, processedRows int64) {
	t.withJob(jobID, func(j *job) {
		j.event.ProcessedRows = processedRows
		if j.event.TotalRows > 0 {
			j.event.Percentage = float64(processedRows) / float64(j.event.TotalRows) * 100
		}
		t.broadcast(j)
	})
}

// MarkCompleted finalises a job as completed.
func (t *Tracker) MarkCompleted(jobID string) {
	now := time.Now()
	t.withJob(jobID, func(j *job) {
		j.event.Status = models.StatusCompleted
		j.event.ProcessedRows = j.event.TotalRows
		j.event.Percentage = 100
		j.event.ProcessingFinishedAt = &now
		t.broadcast(j)
		t.closeSubscribers(j)
	})
}

// MarkFailed marks a job as failed with an error message.
func (t *Tracker) MarkFailed(jobID, errMsg string) {
	now := time.Now()
	t.withJob(jobID, func(j *job) {
		j.event.Status = models.StatusFailed
		j.event.ErrorMessage = errMsg
		j.event.ProcessingFinishedAt = &now
		t.broadcast(j)
		t.closeSubscribers(j)
	})
}

// Subscribe returns a channel that receives events for the given job.
// The caller must call Unsubscribe when done to prevent leaks.
func (t *Tracker) Subscribe(jobID, connID string) (chan Event, Event, bool) {
	t.mu.RLock()
	j, ok := t.jobs[jobID]
	t.mu.RUnlock()
	if !ok {
		return nil, Event{}, false
	}

	ch := make(chan Event, 16)
	j.mu.Lock()
	j.subscribers[connID] = ch
	current := j.event // snapshot of current state
	j.mu.Unlock()

	return ch, current, true
}

// Unsubscribe removes a subscriber channel.
func (t *Tracker) Unsubscribe(jobID, connID string) {
	t.mu.RLock()
	j, ok := t.jobs[jobID]
	t.mu.RUnlock()
	if !ok {
		return
	}
	j.mu.Lock()
	delete(j.subscribers, connID)
	j.mu.Unlock()
}

// Get returns the current snapshot for a job.
func (t *Tracker) Get(jobID string) (Event, bool) {
	t.mu.RLock()
	j, ok := t.jobs[jobID]
	t.mu.RUnlock()
	if !ok {
		return Event{}, false
	}
	j.mu.RLock()
	defer j.mu.RUnlock()
	return j.event, true
}

// --- internal helpers ---

func (t *Tracker) withJob(jobID string, fn func(*job)) {
	t.mu.RLock()
	j, ok := t.jobs[jobID]
	t.mu.RUnlock()
	if !ok {
		return
	}
	j.mu.Lock()
	defer j.mu.Unlock()
	fn(j)
}

func (t *Tracker) broadcast(j *job) {
	snapshot := j.event
	for _, ch := range j.subscribers {
		select {
		case ch <- snapshot:
		default: // drop if subscriber is slow; they'll get the next tick
		}
	}
}

func (t *Tracker) closeSubscribers(j *job) {
	for id, ch := range j.subscribers {
		close(ch)
		delete(j.subscribers, id)
	}
}

