// ─── Upload / Job types ───────────────────────────────────────────────────────

export type UploadStatus =
  | 'pending'
  | 'uploading'
  | 'uploaded'
  | 'processing'
  | 'completed'
  | 'failed';

/** State tracked in the frontend for each queued file. */
export interface FileUploadState {
  /** Stable local key (before the server returns a job_id). */
  localId: string;
  file: File;
  jobId?: string;
  status: UploadStatus;

  /** 0–100, driven by XHR onUploadProgress */
  uploadProgress: number;
  /** 0–100, driven by SSE events from the backend */
  processProgress: number;

  uploadStartTime?: number; // performance.now()
  uploadEndTime?: number;
  uploadDurationMs?: number; // finalised once upload completes

  processDurationMs?: number; // from last SSE event
  overallDurationMs?: number;

  totalRows?: number;
  processedRows?: number;
  error?: string;
}

/** Shape of the SSE payload coming from GET /api/progress/:jobId */
export interface JobEvent {
  job_id: string;
  file_name: string;
  status: UploadStatus;
  total_rows: number;
  processed_rows: number;
  progress_pct: number;
  upload_duration_ms: number;
  process_duration_ms: number;
  overall_duration_ms: number;
  error?: string;
}

// ─── Students types ───────────────────────────────────────────────────────────

export interface Student {
  id: number;
  student_id: string;
  student_name: string;
  subject: string;
  grade: number;
  created_at: string;
}

export interface StudentsResponse {
  data: Student[];
  total: number;
  page: number;
  page_size: number;
  total_pages: number;
}

export interface StudentFilters {
  name: string;
  subject: string;
  gradeGt: string;
  gradeLt: string;
  sortBy: 'student_name' | 'grade';
  sortOrder: 'asc' | 'desc';
  page: number;
  pageSize: number;
}

export const SUBJECTS = [
  'Mathematics',
  'Physics',
  'Chemistry',
  'Biology',
  'History',
  'English Literature',
  'Computer Science',
  'Art',
  'Music',
  'Geography',
] as const;

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react()],
})

package router

import (
	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/config"
	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/handlers"
	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/processing"
	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/repository"
	"github.com/gin-contrib/cors"
	"github.com/gin-gonic/gin"
	"github.com/jackc/pgx/v5/pgxpool"
)

// Setup builds and returns the configured Gin engine.
func Setup(cfg *config.Config, pool *pgxpool.Pool) *gin.Engine {
	r := gin.New()
	r.Use(gin.Logger())
	r.Use(gin.Recovery())

	// Allow the Vite dev server (and any localhost port) during development.
	r.Use(cors.New(cors.Config{
		AllowOrigins:     []string{"http://localhost:5173", "http://localhost:3000"},
		AllowMethods:     []string{"GET", "POST", "DELETE", "OPTIONS"},
		AllowHeaders:     []string{"Origin", "Content-Type", "Accept"},
		ExposeHeaders:    []string{"Content-Length", "Content-Type"},
		AllowCredentials: false,
	}))

	// Increase the multipart memory limit so gin writes large uploads directly
	// to disk instead of keeping them in RAM.
	r.MaxMultipartMemory = 32 << 20 // 32 MB in-memory threshold

	jm := processing.GetJobManager()
	studentRepo := repository.NewStudentRepository(pool)

	api := r.Group("/api")
	{
		api.POST("/upload", handlers.UploadHandler(cfg, pool, jm))
		api.GET("/progress/:jobId", handlers.ProgressHandler(jm))
		api.GET("/students", handlers.ListStudentsHandler(studentRepo))
		api.DELETE("/students", handlers.ClearStudentsHandler(pool))
	}

	// Simple liveness probe.
	r.GET("/health", func(c *gin.Context) {
		c.JSON(200, gin.H{"status": "ok"})
	})

	return r
}

