package handlers

import (
	"net/http"
	"strconv"

	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/models"
	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/repository"
	"github.com/gin-gonic/gin"
)

// ListStudentsHandler handles paginated, sorted, and filtered student queries.
//
// GET /api/students
//
// Query params:
//
//	page       int     (default 1)
//	page_size  int     (default 20, max 100)
//	sort_by    string  "student_name" | "grade"
//	sort_order string  "asc" | "desc"
//	name       string  partial match (case-insensitive)
//	subject    string  exact match
//	grade_gt   int     grade strictly greater than
//	grade_lt   int     grade strictly less than
func ListStudentsHandler(repo *repository.StudentRepository) gin.HandlerFunc {
	return func(c *gin.Context) {
		params := models.ListParams{
			Page:      queryInt(c, "page", 1),
			PageSize:  clamp(queryInt(c, "page_size", 20), 1, 100),
			SortBy:    c.DefaultQuery("sort_by", "student_name"),
			SortOrder: c.DefaultQuery("sort_order", "asc"),
			Name:      c.Query("name"),
			Subject:   c.Query("subject"),
		}

		if v := c.Query("grade_gt"); v != "" {
			if n, err := strconv.Atoi(v); err == nil {
				params.GradeGt = &n
			}
		}

		if v := c.Query("grade_lt"); v != "" {
			if n, err := strconv.Atoi(v); err == nil {
				params.GradeLt = &n
			}
		}

		result, err := repo.List(c.Request.Context(), params)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to list students"})
			return
		}

		c.JSON(http.StatusOK, result)
	}
}

// ----- helpers -----

func queryInt(c *gin.Context, key string, def int) int {
	v := c.Query(key)
	if v == "" {
		return def
	}
	n, err := strconv.Atoi(v)
	if err != nil || n < 1 {
		return def
	}
	return n
}

func clamp(v, min, max int) int {
	if v < min {
		return min
	}
	if v > max {
		return max
	}
	return v
}

package handlers

import (
	"context"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/config"
	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/processing"
	"github.com/gin-gonic/gin"
	"github.com/google/uuid"
	"github.com/jackc/pgx/v5/pgxpool"
)

// UploadHandler accepts a single CSV file, saves it to the temp directory,
// registers a job, and immediately kicks off parallel processing in a goroutine.
//
// Request:  POST /api/upload  (multipart/form-data, field: "file")
// Response: { job_id, file_name, status }
func UploadHandler(cfg *config.Config, pool *pgxpool.Pool, jm *processing.JobManager) gin.HandlerFunc {
	return func(c *gin.Context) {
		uploadStartAt := time.Now()

		fileHeader, err := c.FormFile("file")
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "field 'file' is required"})
			return
		}

		if !strings.HasSuffix(strings.ToLower(fileHeader.Filename), ".csv") {
			c.JSON(http.StatusBadRequest, gin.H{"error": "only .csv files are accepted"})
			return
		}

		src, err := fileHeader.Open()
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "cannot open uploaded file"})
			return
		}
		defer src.Close()

		jobID := uuid.New().String()
		tempPath := filepath.Join(cfg.UploadDir, fmt.Sprintf("%s_%s", jobID, fileHeader.Filename))

		dst, err := os.Create(tempPath)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "cannot create temp file"})
			return
		}

		if _, err := io.Copy(dst, src); err != nil {
			dst.Close()
			os.Remove(tempPath)
			c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to save uploaded file"})
			return
		}
		dst.Close()

		uploadEndAt := time.Now()

		// Register job and record upload timing.
		jm.CreateJob(jobID, fileHeader.Filename, uploadStartAt)
		jm.MarkUploaded(jobID, uploadEndAt)

		// Use a background context so processing is not cancelled when the HTTP
		// response is flushed and the request context is torn down.
		go processing.ProcessFile(context.Background(), jobID, tempPath, pool, jm)

		c.JSON(http.StatusAccepted, gin.H{
			"job_id":    jobID,
			"file_name": fileHeader.Filename,
			"status":    processing.JobStatusUploaded,
		})
	}
}

package processing

import (
	"sync"
	"time"
)

// JobManager is a process-wide singleton that tracks every upload/processing job
// and fans out SSE events to all subscribers of a given job.
type JobManager struct {
	mu   sync.RWMutex
	jobs map[string]*Job
}

var (
	managerInstance *JobManager
	managerOnce    sync.Once
)

// GetJobManager returns the process-wide singleton.
func GetJobManager() *JobManager {
	managerOnce.Do(func() {
		managerInstance = &JobManager{jobs: make(map[string]*Job)}
	})
	return managerInstance
}

// CreateJob registers a new job and returns it. Called by the upload handler.
func (jm *JobManager) CreateJob(jobID, fileName string, uploadStartAt time.Time) *Job {
	job := &Job{
		ID:            jobID,
		FileName:      fileName,
		Status:        JobStatusPending,
		UploadStartAt: uploadStartAt,
		subscribers:   make([]chan JobEvent, 0),
	}

	jm.mu.Lock()
	jm.jobs[jobID] = job
	jm.mu.Unlock()

	return job
}

// GetJob returns the job with the given ID, or nil if not found.
func (jm *JobManager) GetJob(jobID string) *Job {
	jm.mu.RLock()
	defer jm.mu.RUnlock()
	return jm.jobs[jobID]
}

// MarkUploaded records the upload completion time and transitions status to uploaded.
func (jm *JobManager) MarkUploaded(jobID string, uploadEndAt time.Time) {
	job := jm.getJob(jobID)
	if job == nil {
		return
	}

	job.mu.Lock()
	job.UploadEndAt = uploadEndAt
	job.Status = JobStatusUploaded
	job.mu.Unlock()
}

// StartProcessing transitions the job to processing state and records total rows.
func (jm *JobManager) StartProcessing(jobID string, totalRows int64) {
	job := jm.getJob(jobID)
	if job == nil {
		return
	}

	job.mu.Lock()
	job.Status = JobStatusProcessing
	job.TotalRows = totalRows
	job.ProcessStartAt = time.Now()
	event := job.snapshot()
	job.mu.Unlock()

	jm.broadcast(job, event)
}

// UpdateProgress updates the processed row count and broadcasts to subscribers.
func (jm *JobManager) UpdateProgress(jobID string, processedRows int64) {
	job := jm.getJob(jobID)
	if job == nil {
		return
	}

	job.mu.Lock()
	job.ProcessedRows = processedRows
	event := job.snapshot()
	job.mu.Unlock()

	jm.broadcast(job, event)
}

// CompleteJob marks the job as done and broadcasts the final event.
func (jm *JobManager) CompleteJob(jobID string) {
	job := jm.getJob(jobID)
	if job == nil {
		return
	}

	job.mu.Lock()
	job.Status = JobStatusCompleted
	job.ProcessEndAt = time.Now()
	job.ProcessedRows = job.TotalRows
	event := job.snapshot()
	job.mu.Unlock()

	jm.broadcast(job, event)
}

// FailJob marks the job as failed, records the error, and broadcasts.
func (jm *JobManager) FailJob(jobID string, errMsg string) {
	job := jm.getJob(jobID)
	if job == nil {
		return
	}

	job.mu.Lock()
	job.Status = JobStatusFailed
	job.ProcessEndAt = time.Now()
	job.Error = errMsg
	event := job.snapshot()
	job.mu.Unlock()

	jm.broadcast(job, event)
}

// Subscribe returns a channel that will receive JobEvents for the given job
// and a cancel function that removes this subscription.
//
// If the job is already in a terminal state the current snapshot is pushed
// immediately and the returned channel is never written to again.
// If the job does not exist, a closed (empty) channel is returned.
func (jm *JobManager) Subscribe(jobID string) (<-chan JobEvent, func()) {
	job := jm.getJob(jobID)

	ch := make(chan JobEvent, 128)

	if job == nil {
		close(ch)
		return ch, func() {}
	}

	job.mu.Lock()

	// Terminal state: push snapshot and skip subscription.
	if job.Status == JobStatusCompleted || job.Status == JobStatusFailed {
		event := job.snapshot()
		job.mu.Unlock()
		ch <- event
		return ch, func() {}
	}

	// Push the current state so the client has an immediate baseline.
	event := job.snapshot()
	job.subscribers = append(job.subscribers, ch)
	job.mu.Unlock()

	// Non-blocking send of the initial snapshot (buffer is large).
	select {
	case ch <- event:
	default:
	}

	unsub := func() {
		job.mu.Lock()
		defer job.mu.Unlock()
		for i, sub := range job.subscribers {
			if sub == ch {
				job.subscribers = append(job.subscribers[:i], job.subscribers[i+1:]...)
				return
			}
		}
	}

	return ch, unsub
}

// ----- helpers -----

func (jm *JobManager) getJob(jobID string) *Job {
	jm.mu.RLock()
	defer jm.mu.RUnlock()
	return jm.jobs[jobID]
}

// broadcast sends event to every live subscriber of job.
// Non-blocking: slow subscribers are skipped (their channel buffer will catch up).
func (jm *JobManager) broadcast(job *Job, event JobEvent) {
	job.mu.Lock()
	subs := make([]chan JobEvent, len(job.subscribers))
	copy(subs, job.subscribers)
	job.mu.Unlock()

	for _, ch := range subs {
		select {
		case ch <- event:
		default:
		}
	}
}

package processing

import (
	"bytes"
	"context"
	"encoding/csv"
	"fmt"
	"io"
	"os"
	"strconv"
	"strings"

	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
)

const (
	insertBatchSize    = 1000  // rows per pgx CopyFrom call
	progressReportStep = 1.0   // send an SSE event every 1 % of progress
)

// ProcessFile streams the CSV at filePath into PostgreSQL, sending progress
// events via the JobManager.  The temp file is deleted when done.
func ProcessFile(ctx context.Context, jobID, filePath string, pool *pgxpool.Pool, jm *JobManager) {
	defer os.Remove(filePath) // always clean up the temp file

	// --- 1. Count data rows (fast byte scan, no CSV parsing) ---
	totalRows, err := countDataRows(filePath)
	if err != nil {
		jm.FailJob(jobID, fmt.Sprintf("row count failed: %v", err))
		return
	}

	jm.StartProcessing(jobID, totalRows)

	// --- 2. Open and parse the CSV ---
	f, err := os.Open(filePath)
	if err != nil {
		jm.FailJob(jobID, fmt.Sprintf("open file: %v", err))
		return
	}
	defer f.Close()

	reader := csv.NewReader(f)
	reader.FieldsPerRecord = 4
	reader.TrimLeadingSpace = true

	// Skip header row.
	if _, err := reader.Read(); err != nil {
		jm.FailJob(jobID, "failed to read CSV header")
		return
	}

	// --- 3. Stream rows into the database in batches ---
	batch := make([][]any, 0, insertBatchSize)
	var processed int64
	lastReportedPct := float64(-1) // forces the first update to be sent

	for {
		record, err := reader.Read()
		if err == io.EOF {
			break
		}
		if err != nil {
			jm.FailJob(jobID, fmt.Sprintf("CSV parse error: %v", err))
			return
		}

		grade, convErr := strconv.Atoi(strings.TrimSpace(record[3]))
		if convErr != nil {
			continue // skip rows with non-numeric grades
		}

		batch = append(batch, []any{
			strings.TrimSpace(record[0]), // student_id
			strings.TrimSpace(record[1]), // student_name
			strings.TrimSpace(record[2]), // subject
			grade,                        // grade
		})

		if len(batch) >= insertBatchSize {
			if err := bulkInsert(ctx, pool, batch); err != nil {
				jm.FailJob(jobID, fmt.Sprintf("bulk insert: %v", err))
				return
			}
			processed += int64(len(batch))
			batch = batch[:0]

			// Throttle SSE updates to ~1 % increments.
			if totalRows > 0 {
				pct := float64(processed) / float64(totalRows) * 100
				if pct-lastReportedPct >= progressReportStep {
					jm.UpdateProgress(jobID, processed)
					lastReportedPct = pct
				}
			}
		}

		// Respect context cancellation (e.g. client disconnected).
		select {
		case <-ctx.Done():
			jm.FailJob(jobID, "processing cancelled")
			return
		default:
		}
	}

	// Flush the final partial batch.
	if len(batch) > 0 {
		if err := bulkInsert(ctx, pool, batch); err != nil {
			jm.FailJob(jobID, fmt.Sprintf("bulk insert (final): %v", err))
			return
		}
		processed += int64(len(batch))
	}

	jm.CompleteJob(jobID)
}

// bulkInsert uses PostgreSQL's COPY protocol via pgx — much faster than
// individual INSERTs for large datasets.
func bulkInsert(ctx context.Context, pool *pgxpool.Pool, rows [][]any) error {
	_, err := pool.CopyFrom(
		ctx,
		pgx.Identifier{"student_grades"},
		[]string{"student_id", "student_name", "subject", "grade"},
		pgx.CopyFromRows(rows),
	)
	return err
}

// countDataRows counts newline characters to determine the number of data rows
// (total lines minus the header).  This is O(file size) but very fast because
// it operates on raw bytes without any CSV parsing.
func countDataRows(filePath string) (int64, error) {
	f, err := os.Open(filePath)
	if err != nil {
		return 0, err
	}
	defer f.Close()

	buf := make([]byte, 64*1024)
	var count int64
	var lastByte byte = '\n' // treat start-of-file as a newline

	for {
		n, err := f.Read(buf)
		if n > 0 {
			count += int64(bytes.Count(buf[:n], []byte{'\n'}))
			lastByte = buf[n-1]
		}
		if err == io.EOF {
			break
		}
		if err != nil {
			return 0, err
		}
	}

	// If the file doesn't end with a newline, the last line wasn't counted.
	if lastByte != '\n' {
		count++
	}

	// Subtract 1 for the header row.
	if count > 0 {
		count--
	}

	return count, nil
}

package processing

import (
	"sync"
	"time"
)

// JobStatus represents the lifecycle state of an upload/processing job.
type JobStatus string

const (
	JobStatusPending    JobStatus = "pending"
	JobStatusUploaded   JobStatus = "uploaded"
	JobStatusProcessing JobStatus = "processing"
	JobStatusCompleted  JobStatus = "completed"
	JobStatusFailed     JobStatus = "failed"
)

// JobEvent is the payload sent over the SSE stream to the frontend.
type JobEvent struct {
	JobID             string    `json:"job_id"`
	FileName          string    `json:"file_name"`
	Status            JobStatus `json:"status"`
	TotalRows         int64     `json:"total_rows"`
	ProcessedRows     int64     `json:"processed_rows"`
	ProgressPct       float64   `json:"progress_pct"`
	UploadDurationMs  float64   `json:"upload_duration_ms"`
	ProcessDurationMs float64   `json:"process_duration_ms"`
	OverallDurationMs float64   `json:"overall_duration_ms"`
	Error             string    `json:"error,omitempty"`
}

// Job holds the mutable state of one upload + processing job.
// All fields are protected by mu; subscribers is a list of live SSE channels.
type Job struct {
	mu sync.Mutex

	ID             string
	FileName       string
	Status         JobStatus
	TotalRows      int64
	ProcessedRows  int64
	UploadStartAt  time.Time
	UploadEndAt    time.Time
	ProcessStartAt time.Time
	ProcessEndAt   time.Time
	Error          string

	subscribers []chan JobEvent
}

// snapshot builds a JobEvent from the current (already-locked) state.
// Caller must hold j.mu.
func (j *Job) snapshot() JobEvent {
	var uploadMs, processMs float64

	if !j.UploadEndAt.IsZero() && !j.UploadStartAt.IsZero() {
		uploadMs = float64(j.UploadEndAt.Sub(j.UploadStartAt).Milliseconds())
	}

	// While processing is still running, calculate elapsed so far.
	if !j.ProcessStartAt.IsZero() {
		end := j.ProcessEndAt
		if end.IsZero() {
			end = time.Now()
		}
		processMs = float64(end.Sub(j.ProcessStartAt).Milliseconds())
	}

	var pct float64
	if j.TotalRows > 0 {
		pct = float64(j.ProcessedRows) / float64(j.TotalRows) * 100
		if pct > 100 {
			pct = 100
		}
	}

	return JobEvent{
		JobID:             j.ID,
		FileName:          j.FileName,
		Status:            j.Status,
		TotalRows:         j.TotalRows,
		ProcessedRows:     j.ProcessedRows,
		ProgressPct:       pct,
		UploadDurationMs:  uploadMs,
		ProcessDurationMs: processMs,
		OverallDurationMs: uploadMs + processMs,
		Error:             j.Error,
	}
}

package repository

import (
	"context"
	"fmt"
	"math"
	"strings"

	"github.com/YoussefGaafar/file-upload-fullstack/backend/internal/models"
	"github.com/jackc/pgx/v5/pgxpool"
)

type StudentRepository struct {
	pool *pgxpool.Pool
}

func NewStudentRepository(pool *pgxpool.Pool) *StudentRepository {
	return &StudentRepository{pool: pool}
}

// allowedSortColumns is a whitelist to prevent SQL injection via sort column.
var allowedSortColumns = map[string]string{
	"student_name": "student_name",
	"grade":        "grade",
}

// List returns a paginated, sorted, and filtered slice of students together
// with the total count matching the filters.
func (r *StudentRepository) List(ctx context.Context, p models.ListParams) (models.ListResponse, error) {
	// --- Build WHERE clause with positional parameters ---
	where := []string{"1=1"}
	args := []any{}
	idx := 1

	if p.Name != "" {
		where = append(where, fmt.Sprintf("student_name ILIKE $%d", idx))
		args = append(args, "%"+p.Name+"%")
		idx++
	}

	if p.Subject != "" {
		where = append(where, fmt.Sprintf("subject = $%d", idx))
		args = append(args, p.Subject)
		idx++
	}

	if p.GradeGt != nil {
		where = append(where, fmt.Sprintf("grade > $%d", idx))
		args = append(args, *p.GradeGt)
		idx++
	}

	if p.GradeLt != nil {
		where = append(where, fmt.Sprintf("grade < $%d", idx))
		args = append(args, *p.GradeLt)
		idx++
	}

	whereClause := strings.Join(where, " AND ")

	// --- COUNT ---
	var total int64
	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM student_grades WHERE %s", whereClause)
	if err := r.pool.QueryRow(ctx, countQuery, args...).Scan(&total); err != nil {
		return models.ListResponse{}, fmt.Errorf("count query: %w", err)
	}

	// --- Validate and sanitise sort parameters ---
	sortCol, ok := allowedSortColumns[p.SortBy]
	if !ok {
		sortCol = "student_name"
	}

	sortDir := "ASC"
	if strings.ToLower(p.SortOrder) == "desc" {
		sortDir = "DESC"
	}

	// --- Pagination ---
	if p.Page < 1 {
		p.Page = 1
	}
	if p.PageSize < 1 {
		p.PageSize = 20
	}
	offset := (p.Page - 1) * p.PageSize

	// --- DATA query ---
	dataQuery := fmt.Sprintf(
		`SELECT id, student_id, student_name, subject, grade, created_at
		 FROM student_grades
		 WHERE %s
		 ORDER BY %s %s
		 LIMIT $%d OFFSET $%d`,
		whereClause, sortCol, sortDir, idx, idx+1,
	)
	args = append(args, p.PageSize, offset)

	rows, err := r.pool.Query(ctx, dataQuery, args...)
	if err != nil {
		return models.ListResponse{}, fmt.Errorf("data query: %w", err)
	}
	defer rows.Close()

	students := make([]models.Student, 0, p.PageSize)
	for rows.Next() {
		var s models.Student
		if err := rows.Scan(
			&s.ID, &s.StudentID, &s.StudentName, &s.Subject, &s.Grade, &s.CreatedAt,
		); err != nil {
			return models.ListResponse{}, fmt.Errorf("scan row: %w", err)
		}
		students = append(students, s)
	}
	if err := rows.Err(); err != nil {
		return models.ListResponse{}, fmt.Errorf("rows iteration: %w", err)
	}

	totalPages := int64(math.Ceil(float64(total) / float64(p.PageSize)))

	return models.ListResponse{
		Data:       students,
		Total:      total,
		Page:       p.Page,
		PageSize:   p.PageSize,
		TotalPages: totalPages,
	}, nil
}

package models

import "time"

// Student represents a single row in the student_grades table.
type Student struct {
	ID          int64     `json:"id"`
	StudentID   string    `json:"student_id"`
	StudentName string    `json:"student_name"`
	Subject     string    `json:"subject"`
	Grade       int       `json:"grade"`
	CreatedAt   time.Time `json:"created_at"`
}

// ListParams holds all query parameters for listing students.
type ListParams struct {
	Page      int
	PageSize  int
	SortBy    string // "student_name" | "grade"
	SortOrder string // "asc" | "desc"
	Name      string
	Subject   string
	GradeGt   *int
	GradeLt   *int
}

// ListResponse is the paginated response for the students endpoint.
type ListResponse struct {
	Data       []Student `json:"data"`
	Total      int64     `json:"total"`
	Page       int       `json:"page"`
	PageSize   int       `json:"page_size"`
	TotalPages int64     `json:"total_pages"`
}

package config

import (
	"fmt"
	"os"

	"github.com/joho/godotenv"
)

type Config struct {
	DatabaseURL string
	Port        string
	UploadDir   string
}

func Load() (*Config, error) {
	// Load .env file if it exists; ignore error if it doesn't.
	_ = godotenv.Load()

	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		return nil, fmt.Errorf("DATABASE_URL environment variable is required")
	}

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	uploadDir := os.Getenv("UPLOAD_DIR")
	if uploadDir == "" {
		uploadDir = "/tmp/uploads"
	}

	return &Config{
		DatabaseURL: dbURL,
		Port:        port,
		UploadDir:   uploadDir,
	}, nil
}

